import React, { useState, useEffect, useCallback } from "react";
import axios from "axios";
import { ResponsiveContainer, AreaChart, Area, YAxis } from "recharts";
import { Bitcoin, Coins, CircleDot, Database, Smartphone, XCircle } from "lucide-react";
import "../../styles/financecoin.css";

const COIN_CONFIGS = [
  { pair: "BTCUSDT", name: "BITCOIN", symbol: "BTC", icon: Bitcoin, color: "#F7931A" },
  { pair: "ETHUSDT", name: "ETHEREUM", symbol: "ETH", icon: Coins, color: "#627EEA" },
  { pair: "SOLUSDT", name: "SOLANA", symbol: "SOL", icon: Smartphone, color: "#14F195" },
  { pair: "BNBUSDT", name: "BINANCE COIN", symbol: "BNB", icon: CircleDot, color: "#F3BA2F" },
  { pair: "ADAUSDT", name: "CARDANO", symbol: "ADA", icon: Database, color: "#0033AD" },
  { pair: "XRPUSDT", name: "XRP", symbol: "XRP", icon: XCircle, color: "#ffffff" }
];

const CryptoBox = ({ coin }) => {
  const Icon = coin.icon;
  const isPositive = parseFloat(coin.priceChangePercent) >= 0;

  return (
    <div className="crypto-item-box">
      <div className="coin-left-section">
        <div 
          className="coin-icon-wrapper" 
          style={{ background: `linear-gradient(135deg, ${coin.color}33, ${coin.color}11)` }}
        >
          <Icon size={28} color={coin.color} />
        </div>
        <div className="coin-details">
          <h3 className="coin-title">{coin.name} ({coin.symbol})</h3>
          <div className="price-info">
            <span className="coin-price">
              ${parseFloat(coin.lastPrice).toLocaleString("en-US")}
            </span>
            <span className={`coin-change ${isPositive ? "up" : "down"}`}>
              {isPositive ? "+" : ""}{parseFloat(coin.priceChangePercent).toFixed(2)}%
            </span>
          </div>
        </div>
      </div>

      <div className="coin-right-section">
        <ResponsiveContainer width="100%" height={60}>
          <AreaChart data={coin.history}>
            <defs>
              <linearGradient id={`color-${coin.symbol}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={coin.color} stopOpacity={0.3} />
                <stop offset="95%" stopColor={coin.color} stopOpacity={0} />
              </linearGradient>
            </defs>
            <YAxis hide domain={["dataMin", "dataMax"]} />
            <Area
              type="monotone"
              dataKey="price"
              stroke={coin.color}
              fill={`url(#color-${coin.symbol})`}
              strokeWidth={2}
              dot={false}
              isAnimationActive={true}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default function FinanceCoin() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = useCallback(async () => {
    try {
      // Binance API üzerinden ticker verilerini al
      const tickerRes = await axios.get("https://api.binance.com/api/v3/ticker/24hr");
      
      const fullCoinsData = await Promise.all(
        COIN_CONFIGS.map(async (config) => {
          const ticker = tickerRes.data.find(t => t.symbol === config.pair);
          
          try {
            // Son 24 saatlik grafik verisi (1 saatlik aralıklarla)
            const graphRes = await axios.get(
              `https://api.binance.com/api/v3/klines?symbol=${config.pair}&interval=1h&limit=24`
            );
            
            const history = graphRes.data.map(item => ({
              price: parseFloat(item[4]) // Kapanış fiyatı
            }));

            return { ...config, ...ticker, history };
          } catch (e) {
            return { ...config, ...ticker, history: [] };
          }
        })
      );

      setData(fullCoinsData);
      setLoading(false);
    } catch (err) {
      console.error("Veri çekme hatası:", err);
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, [fetchData]);

  if (loading) return <div className="loader">Veriler Hazırlanıyor...</div>;

  return (
    <div className="market-insight-wrapper">
      <div className="market-header">
        <h2 className="market-main-title">CRYPTO MARKET INSIGHTS</h2>
        <div className="live-indicator"><span>●</span> LIVE</div>
      </div>
      <div className="crypto-boxes-container">
        {data.map((coin) => (
          <CryptoBox key={coin.pair} coin={coin} />
        ))}
      </div>
    </div>
  );
}
